def removeInvalidParentheses(s):
    def isValid(s):
        cnt = 0
        for c in s:
            if c == "(" : cnt += 1
            elif c == ")": cnt -= 1
            if cnt < 0: return False
        return cnt == 0
    q, seen, res = {s}, {s}, []
    while q:
        nxt = set()
        for x in q:
            if isValid(x): res.append(x)
        if res: return res
        for x in q:
            for i in range(len(x)):
                if x[i] in "()":
                    t = x[:i] + x[i+1:]
                    if t not in seen: seen.add(t); nxt.add(t)
        q = nxt
    return [""]

